code = """import json

# Get the data from the last query
data = locals()['var_functions.query_db_52']

# Count transfers and cases per agent
transfer_counts = {}
case_counts = {}

for record in data:
    old_agent = record['oldvalue__c']
    new_agent = record['newvalue__c']
    
    # Count cases handled by agent (receiving)
    if new_agent != 'None':
        case_counts[new_agent] = case_counts.get(new_agent, 0) + 1
    
    # Count transfers made by agent (sending)
    if old_agent != 'None':
        transfer_counts[old_agent] = transfer_counts.get(old_agent, 0) + 1

# Filter for agents with > 0 cases
candidates = [(agent_id, transfer_counts.get(agent_id, 0)) for agent_id in case_counts if case_counts[agent_id] > 0]

# Sort by transfer count (ascending) then agent ID
candidates.sort(key=lambda x: (x[1], x[0]))

# Get result
result_agent = candidates[0][0] if candidates else None

# Format output
print("__RESULT__:")
print(json.dumps(result_agent))"""

